<div class="wdl-library wdl-cards"><?php if($data['query']->have_posts()): while($data['query']->have_posts()):$data['query']->the_post(); $u=get_post_meta(get_the_ID(),'_wdl_file_url',true);?><article class="wdl-document-card"><?php echo $data['helpers']->get_thumb_or_icon(get_the_ID(),$u,'medium');?><h3><?php the_title();?></h3><p><?php echo esc_html(get_post_meta(get_the_ID(),'_wdl_card_description',true));?></p><a class="wdl-button" href="<?php echo esc_url(get_permalink());?>">Открыть</a></article><?php endwhile; else: ?><div>Документы не найдены</div><?php endif;?></div>
